// Initialize system parameters and global variables
const startup = {
    timestamp: new Date().toISOString(),
    version: '1.0.0',
    system: 'Industrial Modbus Power Control',
    devices: {
        'Huawei SmartLogger 3000A': {
            ip: '192.168.88.4',
            status: 'initializing'
        },
        'SICES GC600': {
            ip: '192.168.88.6', 
            status: 'initializing'
        },
        'SICES MC200': {
            ip: '192.168.88.7',
            status: 'initializing'
        }
    }
};

// Initialize global variables
global.set('devices', {});
global.set('control', {
    zeroExportThreshold: 50,
    loadShareRampRate: 1.0,
    gensetMinRunTime: 300,
    gensetCooldownTime: 120,
    pvPriority: true,
    gensetRunning: false,
    lastGensetStop: 0
});
global.set('manualOverride', {});
global.set('systemStatus', 'starting');

node.log('Industrial Modbus Power Control System Starting...');
node.log('Huawei SmartLogger 3000A: 192.168.88.4');
node.log('SICES GC600: 192.168.88.6');
node.log('SICES MC200: 192.168.88.7');

msg.payload = startup;
return msg;

// Monitor system health and device connectivity
const devices = global.get('devices') || {};
const now = Date.now();
const healthReport = {
    timestamp: new Date().toISOString(),
    system_uptime: process.uptime(),
    devices: {},
    overall_status: 'healthy'
};

// Check each device's last update time
Object.keys(devices).forEach(deviceName => {
    const device = devices[deviceName];
    const lastUpdate = new Date(device.timestamp).getTime();
    const timeSinceUpdate = now - lastUpdate;

    healthReport.devices[deviceName] = {
        last_update: device.timestamp,
        seconds_since_update: Math.round(timeSinceUpdate / 1000),
        status: timeSinceUpdate < 30000 ? 'online' : 'offline'
    };

    if (timeSinceUpdate > 30000) {
        healthReport.overall_status = 'degraded';
    }
});

// Check if any devices are missing
const expectedDevices = ['Huawei SmartLogger 3000A', 'SICES GC600', 'SICES MC200'];
expectedDevices.forEach(deviceName => {
    if (!devices[deviceName]) {
        healthReport.devices[deviceName] = {
            status: 'no_data',
            last_update: null,
            seconds_since_update: null
        };
        healthReport.overall_status = 'critical';
    }
});

global.set('systemHealth', healthReport);

if (healthReport.overall_status !== 'healthy') {
    node.warn(`System health status: ${healthReport.overall_status}`);
}

msg.payload = healthReport;
return msg;
